import face_recognition
import numpy as np
import os
import joblib
from sklearn import svm
from sklearn.preprocessing import LabelEncoder
from flask import Flask, request, jsonify
from io import BytesIO
from PIL import Image

# --- Configuration ---
DATASET_PATH = "dataset"  # Path to your employee photos dataset
MODEL_PATH = "face_recognition_model.pkl"
LABEL_ENCODER_PATH = "label_encoder.pkl"

# --- Part 1: Model Training Script (train_model.py) ---

def train_face_recognizer():
    """
    Trains a facial recognition model using employee photos from the DATASET_PATH.
    Each subdirectory in DATASET_PATH is considered a unique employee.
    """
    print("Starting model training...")
    known_face_encodings = []
    known_face_names = []

    if not os.path.exists(DATASET_PATH):
        print(f"Error: Dataset path '{DATASET_PATH}' does not exist.")
        print("Please create a 'dataset' directory with subdirectories for each employee.")
        print("Example: dataset/John_Doe/photo1.jpg, dataset/Jane_Smith/photo2.png")
        return

    # Iterate through each employee's directory
    for name in os.listdir(DATASET_PATH):
        person_dir = os.path.join(DATASET_PATH, name)
        if not os.path.isdir(person_dir):
            continue

        print(f"Processing photos for: {name}")
        for filename in os.listdir(person_dir):
            if not (filename.lower().endswith(".jpg") or filename.lower().endswith(".png")):
                continue

            image_path = os.path.join(person_dir, filename)
            try:
                image = face_recognition.load_image_file(image_path)
                face_locations = face_recognition.face_locations(image)

                if len(face_locations) == 0:
                    print(f"  Warning: No face found in {image_path}. Skipping.")
                    continue
                elif len(face_locations) > 1:
                    print(f"  Warning: Multiple faces found in {image_path}. Using the first one.")

                face_encoding = face_recognition.face_encodings(image, face_locations)[0]
                known_face_encodings.append(face_encoding)
                known_face_names.append(name)
                print(f"  Encoded: {image_path}")

            except Exception as e:
                print(f"  Error processing {image_path}: {e}")

    if not known_face_encodings:
        print("No face encodings found. Training aborted.")
        return

    # Encode names to numerical labels
    label_encoder = LabelEncoder()
    labels = label_encoder.fit_transform(known_face_names)

    # Train a Support Vector Machine (SVM) classifier
    # probability=True is essential for getting confidence scores
    classifier = svm.SVC(gamma='scale', probability=True, random_state=42)
    classifier.fit(known_face_encodings, labels)

    # Save the trained model and label encoder
    joblib.dump(classifier, MODEL_PATH)
    joblib.dump(label_encoder, LABEL_ENCODER_PATH)

    print(f"\nTraining complete. Model saved to '{MODEL_PATH}'")
    print(f"Label encoder saved to '{LABEL_ENCODER_PATH}'")
    print(f"Trained on {len(known_face_encodings)} faces from {len(label_encoder.classes_)} employees.")

# --- Part 2: Flask API (app.py) ---

app = Flask(__name__)

# Global variables to hold the loaded model and label encoder
classifier = None
label_encoder = None

@app.before_first_request
def load_model():
    """
    Loads the trained model and label encoder when the Flask app starts.
    """
    global classifier, label_encoder
    try:
        classifier = joblib.load(MODEL_PATH)
        label_encoder = joblib.load(LABEL_ENCODER_PATH)
        print("Facial recognition model loaded successfully.")
    except FileNotFoundError:
        print(f"Error: Model files '{MODEL_PATH}' or '{LABEL_ENCODER_PATH}' not found.")
        print("Please run 'train_face_recognizer()' first to train the model.")
        classifier = None
        label_encoder = None
    except Exception as e:
        print(f"An error occurred loading the model: {e}")
        classifier = None
        label_encoder = None

@app.route('/recognize', methods=['POST'])
def recognize_face():
    """
    API endpoint to recognize faces in an uploaded image.
    Returns confidence scores for all known employees for each detected face.
    """
    if classifier is None or label_encoder is None:
        return jsonify({"error": "Model not loaded. Please train the model first."}), 500

    if 'image' not in request.files:
        return jsonify({"error": "No image file provided"}), 400

    file = request.files['image']
    if file.filename == '':
        return jsonify({"error": "No selected file"}), 400

    try:
        # Read the image file and convert to a numpy array
        image_bytes = file.read()
        pil_image = Image.open(BytesIO(image_bytes))
        # Ensure image is RGB for face_recognition library
        if pil_image.mode != 'RGB':
            pil_image = pil_image.convert('RGB')
        
        # Convert PIL Image to numpy array
        # face_recognition expects images in RGB (height, width, 3)
        np_image = np.array(pil_image)

        # Find all face locations and encodings in the uploaded image
        face_locations = face_recognition.face_locations(np_image)
        face_encodings = face_recognition.face_encodings(np_image, face_locations)

        if not face_encodings:
            return jsonify({"detections": []}), 200 # No faces found

        results = []
        for face_encoding in face_encodings:
            # Predict probabilities for all known classes
            probabilities = classifier.predict_proba([face_encoding])[0]

            # Create a detailed probability distribution
            distribution = {}
            for i, prob in enumerate(probabilities):
                employee_name = label_encoder.inverse_transform([i])[0]
                distribution[employee_name] = round(prob, 4) # Round for cleaner output

            # Optionally, get the best match (highest probability)
            best_match_index = np.argmax(probabilities)
            best_match_name = label_encoder.inverse_transform([best_match_index])[0]
            best_match_confidence = round(probabilities[best_match_index], 4)

            results.append({
                "best_match": {
                    "name": best_match_name,
                    "confidence": best_match_confidence
                },
                "full_distribution": distribution
            })

        return jsonify({"detections": results}), 200

    except Exception as e:
        return jsonify({"error": f"An error occurred during recognition: {e}"}), 500

